// Level 7, 2-bit — needed for polar3 dim=256
static constexpr float POLARQ_CENTROIDS_L7_2BIT[4] = {0.69146830f, 0.75732541f, 0.81385344f, 0.87985408f};
static constexpr float POLARQ_BOUNDARIES_L7_2BIT[3] = {0.72439682f, 0.78558940f, 0.84685373f};
