static constexpr float POLARQ_SIN_L7_2BIT[4] = {0.63766891f, 0.68698037f, 0.72693872f, 0.77064592f};

// -----------------------------------------------------------------------
// Bit allocation tables — dim-specific.
// -----------------------------------------------------------------------
static constexpr int POLARQ_MAX_LEVELS = 8;

// Optimal allocations from exhaustive search (DiagnosticAllocationSearch).
// polar4/128: [5,3,3,3,3,5,2] RMSE=0.098 vs TBQ4 RMSE=0.096 — parity.
static constexpr int POLARQ_BITS_POLAR4_128[POLARQ_MAX_LEVELS] = {5, 3, 3, 3, 3, 5, 2, 0};
// polar4/256: same pattern extended; L8 gets 0 (fixed).
// @todo claude: run exhaustive search for dim=256 to validate
static constexpr int POLARQ_BITS_POLAR4_256[POLARQ_MAX_LEVELS] = {5, 3, 3, 3, 3, 5, 2, 0};
// polar3/128: [4,2,2,3,2,0,0] RMSE=0.230 (best found, still behind TBQ3 0.183).
static constexpr int POLARQ_BITS_POLAR3_128[POLARQ_MAX_LEVELS] = {4, 2, 2, 3, 2, 0, 0, 0};
// polar3/256: extended for L=8.
// @todo claude: run exhaustive search for dim=256
static constexpr int POLARQ_BITS_POLAR3_256[POLARQ_MAX_LEVELS] = {4, 2, 2, 3, 2, 2, 2, 0};

static inline const int* polarq_get_bits_per_level(int bits, int head_dim) {
    if (bits == 4)
        return (head_dim <= 128) ? POLARQ_BITS_POLAR4_128 : POLARQ_BITS_POLAR4_256;
    return (head_dim <= 128) ? POLARQ_BITS_POLAR3_128 : POLARQ_BITS_POLAR3_256;
}

static constexpr float POLARQ_FIXED_ANGLE = 0.78539816339744830962f;
static constexpr float POLARQ_FIXED_COS = 0.70710678118654752440f;
static constexpr float POLARQ_FIXED_SIN = 0.70710678118654752440f;

// -----------------------------------------------------------------------
// LUT accessor.
// -----------------------------------------------------------------------

struct PolarqLevelLUT {
    const float* centroids;
    const float* boundaries;
    const float* cos_lut;
    const float* sin_lut;
    int n_centroids;
};

static inline PolarqLevelLUT polarq_get_lut(int level_1based, int bits) {
    if (bits == 0)
        return {nullptr, nullptr, nullptr, nullptr, 0};
    switch (level_1based * 16 + bits) {
    case 1 * 16 + 3:
        return {POLARQ_CENTROIDS_L1_3BIT, POLARQ_BOUNDARIES_L1_3BIT, POLARQ_COS_L1_3BIT, POLARQ_SIN_L1_3BIT, 8};
    case 1 * 16 + 4:
        return {POLARQ_CENTROIDS_L1_4BIT, POLARQ_BOUNDARIES_L1_4BIT, POLARQ_COS_L1_4BIT, POLARQ_SIN_L1_4BIT, 16};
    case 1 * 16 + 5:
        return {POLARQ_CENTROIDS_L1_5BIT, POLARQ_BOUNDARIES_L1_5BIT, POLARQ_COS_L1_5BIT, POLARQ_SIN_L1_5BIT, 32};
    case 2 * 16 + 2:
        return {POLARQ_CENTROIDS_L2_2BIT, POLARQ_BOUNDARIES_L2_2BIT, POLARQ_COS_L2_2BIT, POLARQ_SIN_L2_2BIT, 4};
    case 2 * 16 + 3:
        return {POLARQ_CENTROIDS_L2_3BIT, POLARQ_BOUNDARIES_L2_3BIT, POLARQ_COS_L2_3BIT, POLARQ_SIN_L2_3BIT, 8};
    case 2 * 16 + 5:
        return {POLARQ_CENTROIDS_L2_5BIT, POLARQ_BOUNDARIES_L2_5BIT, POLARQ_COS_L2_5BIT, POLARQ_SIN_L2_5BIT, 32};
    case 3 * 16 + 2:
        return {POLARQ_CENTROIDS_L3_2BIT, POLARQ_BOUNDARIES_L3_2BIT, POLARQ_COS_L3_2BIT, POLARQ_SIN_L3_2BIT, 4};
    case 3 * 16 + 3:
        return {POLARQ_CENTROIDS_L3_3BIT, POLARQ_BOUNDARIES_L3_3BIT, POLARQ_COS_L3_3BIT, POLARQ_SIN_L3_3BIT, 8};
    case 3 * 16 + 4:
        return {POLARQ_CENTROIDS_L3_4BIT, POLARQ_BOUNDARIES_L3_4BIT, POLARQ_COS_L3_4BIT, POLARQ_SIN_L3_4BIT, 16};
    case 4 * 16 + 3:
        return {POLARQ_CENTROIDS_L4_3BIT, POLARQ_BOUNDARIES_L4_3BIT, POLARQ_COS_L4_3BIT, POLARQ_SIN_L4_3BIT, 8};
    case 5 * 16 + 2:
        return {POLARQ_CENTROIDS_L5_2BIT, POLARQ_BOUNDARIES_L5_2BIT, POLARQ_COS_L5_2BIT, POLARQ_SIN_L5_2BIT, 4};
    case 5 * 16 + 3:
        return {POLARQ_CENTROIDS_L5_3BIT, POLARQ_BOUNDARIES_L5_3BIT, POLARQ_COS_L5_3BIT, POLARQ_SIN_L5_3BIT, 8};
    case 6 * 16 + 2:
        return {POLARQ_CENTROIDS_L6_2BIT, POLARQ_BOUNDARIES_L6_2BIT, POLARQ_COS_L6_2BIT, POLARQ_SIN_L6_2BIT, 4};
    case 6 * 16 + 3:
        return {POLARQ_CENTROIDS_L6_3BIT, POLARQ_BOUNDARIES_L6_3BIT, POLARQ_COS_L6_3BIT, POLARQ_SIN_L6_3BIT, 8};
    case 6 * 16 + 5:
        return {POLARQ_CENTROIDS_L6_5BIT, POLARQ_BOUNDARIES_L6_5BIT, POLARQ_COS_L6_5BIT, POLARQ_SIN_L6_5BIT, 32};
    case 7 * 16 + 2:
        return {POLARQ_CENTROIDS_L7_2BIT, POLARQ_BOUNDARIES_L7_2BIT, POLARQ_COS_L7_2BIT, POLARQ_SIN_L7_2BIT, 4};
    default:
        return {nullptr, nullptr, nullptr, nullptr, 0};
    }
}

// -----------------------------------------------------------------------
// Compute packed head record size in bytes.
// Each level is individually byte-rounded when packed.
// -----------------------------------------------------------------------
static inline size_t polarq_head_bytes_from_alloc(int head_dim, const int* bits_per_level) {
    size_t total_bytes = 0;
    int L = 0;
    for (int d = head_dim; d > 1; d >>= 1)
        L++;
    for (int k = 0; k < L; k++) {
        int n_bits = (head_dim >> (k + 1)) * bits_per_level[k];
        total_bytes += static_cast<size_t>((n_bits + 7) / 8);
    }
    return total_bytes + 4;  // + fp32 norm
}
